/**
 * TextEffectsPanel — Painel de efeitos de texto (shadow, outline, gradient)
 *
 * Cada seção permite configurar um tipo de efeito com sliders e color pickers.
 * Preview em tempo real mostra o texto com todos os efeitos ativos.
 * Funções puras de criação de defaults são exportadas para testes.
 */

'use client';

import React, { useState, useCallback, useMemo } from 'react';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Slider } from '@/components/ui/slider';
import { Separator } from '@/components/ui/separator';
import { Switch } from '@/components/ui/switch';
import { cn } from '@/lib/utils';
import {
  type TextEffect,
  type TextShadowEffect,
  type TextOutlineEffect,
  type TextGradientEffect,
  type GradientDirection,
  mergeTextEffects,
} from '@/lib/typography/font-manager';

// ─── Pure helpers (exportados para testes) ─────────────────────────

/**
 * Cria um TextShadowEffect com valores padrão.
 */
export function createDefaultShadow(): TextShadowEffect {
  return {
    type: 'shadow',
    offsetX: 2,
    offsetY: 2,
    blur: 4,
    color: 'rgba(0,0,0,0.5)',
  };
}

/**
 * Cria um TextOutlineEffect com valores padrão.
 */
export function createDefaultOutline(): TextOutlineEffect {
  return {
    type: 'outline',
    width: 1,
    color: '#000000',
  };
}

/**
 * Cria um TextGradientEffect com valores padrão.
 */
export function createDefaultGradient(): TextGradientEffect {
  return {
    type: 'gradient',
    startColor: '#3B82F6',
    endColor: '#8B5CF6',
    direction: 'horizontal',
  };
}

/**
 * Coleta os efeitos ativos em um array.
 */
export function collectActiveEffects(
  shadowEnabled: boolean,
  shadow: TextShadowEffect,
  outlineEnabled: boolean,
  outline: TextOutlineEffect,
  gradientEnabled: boolean,
  gradient: TextGradientEffect,
): TextEffect[] {
  const effects: TextEffect[] = [];
  if (shadowEnabled) effects.push(shadow);
  if (outlineEnabled) effects.push(outline);
  if (gradientEnabled) effects.push(gradient);
  return effects;
}

// ─── Types ─────────────────────────────────────────────────────────

export interface TextEffectsPanelProps {
  /** Efeitos iniciais */
  initialEffects?: TextEffect[];
  /** Callback ao mudar efeitos */
  onEffectChange: (effects: TextEffect[]) => void;
  /** Texto de preview */
  previewText?: string;
  /** Classes CSS adicionais */
  className?: string;
}

// ─── Gradient Direction Options ────────────────────────────────────

const GRADIENT_DIRECTIONS: ReadonlyArray<{ value: GradientDirection; label: string }> = [
  { value: 'horizontal', label: 'Horizontal' },
  { value: 'vertical', label: 'Vertical' },
  { value: 'diagonal', label: 'Diagonal' },
];

// ─── Component ─────────────────────────────────────────────────────

export function TextEffectsPanel({
  initialEffects = [],
  onEffectChange,
  previewText = 'Texto com efeitos',
  className,
}: TextEffectsPanelProps) {
  // Initialize from initial effects
  const initialShadow = initialEffects.find((e): e is TextShadowEffect => e.type === 'shadow');
  const initialOutline = initialEffects.find((e): e is TextOutlineEffect => e.type === 'outline');
  const initialGradient = initialEffects.find((e): e is TextGradientEffect => e.type === 'gradient');

  const [shadowEnabled, setShadowEnabled] = useState(!!initialShadow);
  const [shadow, setShadow] = useState<TextShadowEffect>(initialShadow ?? createDefaultShadow());

  const [outlineEnabled, setOutlineEnabled] = useState(!!initialOutline);
  const [outline, setOutline] = useState<TextOutlineEffect>(initialOutline ?? createDefaultOutline());

  const [gradientEnabled, setGradientEnabled] = useState(!!initialGradient);
  const [gradient, setGradient] = useState<TextGradientEffect>(
    initialGradient ?? createDefaultGradient(),
  );

  const emitChange = useCallback(
    (
      sEnabled: boolean,
      s: TextShadowEffect,
      oEnabled: boolean,
      o: TextOutlineEffect,
      gEnabled: boolean,
      g: TextGradientEffect,
    ) => {
      onEffectChange(collectActiveEffects(sEnabled, s, oEnabled, o, gEnabled, g));
    },
    [onEffectChange],
  );

  // ─── Shadow handlers ──────────────────────────────

  const handleShadowToggle = useCallback(
    (checked: boolean) => {
      setShadowEnabled(checked);
      emitChange(checked, shadow, outlineEnabled, outline, gradientEnabled, gradient);
    },
    [shadow, outlineEnabled, outline, gradientEnabled, gradient, emitChange],
  );

  const updateShadow = useCallback(
    (partial: Partial<TextShadowEffect>) => {
      const next = { ...shadow, ...partial };
      setShadow(next);
      emitChange(shadowEnabled, next, outlineEnabled, outline, gradientEnabled, gradient);
    },
    [shadow, shadowEnabled, outlineEnabled, outline, gradientEnabled, gradient, emitChange],
  );

  // ─── Outline handlers ─────────────────────────────

  const handleOutlineToggle = useCallback(
    (checked: boolean) => {
      setOutlineEnabled(checked);
      emitChange(shadowEnabled, shadow, checked, outline, gradientEnabled, gradient);
    },
    [shadowEnabled, shadow, outline, gradientEnabled, gradient, emitChange],
  );

  const updateOutline = useCallback(
    (partial: Partial<TextOutlineEffect>) => {
      const next = { ...outline, ...partial };
      setOutline(next);
      emitChange(shadowEnabled, shadow, outlineEnabled, next, gradientEnabled, gradient);
    },
    [outline, shadowEnabled, shadow, outlineEnabled, gradientEnabled, gradient, emitChange],
  );

  // ─── Gradient handlers ────────────────────────────

  const handleGradientToggle = useCallback(
    (checked: boolean) => {
      setGradientEnabled(checked);
      emitChange(shadowEnabled, shadow, outlineEnabled, outline, checked, gradient);
    },
    [shadowEnabled, shadow, outlineEnabled, outline, gradient, emitChange],
  );

  const updateGradient = useCallback(
    (partial: Partial<TextGradientEffect>) => {
      const next = { ...gradient, ...partial };
      setGradient(next);
      emitChange(shadowEnabled, shadow, outlineEnabled, outline, gradientEnabled, next);
    },
    [gradient, shadowEnabled, shadow, outlineEnabled, outline, gradientEnabled, emitChange],
  );

  // ─── Preview ──────────────────────────────────────

  const previewStyle = useMemo(() => {
    const effects = collectActiveEffects(
      shadowEnabled,
      shadow,
      outlineEnabled,
      outline,
      gradientEnabled,
      gradient,
    );
    return {
      fontSize: '24px',
      fontWeight: 700,
      ...mergeTextEffects(effects),
    };
  }, [shadowEnabled, shadow, outlineEnabled, outline, gradientEnabled, gradient]);

  return (
    <div className={cn('flex flex-col gap-4 rounded-lg bg-zinc-900 p-4 border border-zinc-700', className)}>
      <Label className="text-sm font-medium text-zinc-300">Efeitos de Texto</Label>

      {/* ─── Shadow Section ─── */}
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <Label className="text-xs text-zinc-400">Sombra</Label>
          <Switch checked={shadowEnabled} onCheckedChange={handleShadowToggle} />
        </div>
        {shadowEnabled && (
          <div className="flex flex-col gap-2 pl-2">
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Offset X</Label>
              <Slider
                min={-20}
                max={20}
                step={1}
                value={[shadow.offsetX]}
                onValueChange={([v]: number[]) => updateShadow({ offsetX: v })}
                className="flex-1"
              />
              <span className="w-8 text-right text-xs text-zinc-500">{shadow.offsetX}</span>
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Offset Y</Label>
              <Slider
                min={-20}
                max={20}
                step={1}
                value={[shadow.offsetY]}
                onValueChange={([v]: number[]) => updateShadow({ offsetY: v })}
                className="flex-1"
              />
              <span className="w-8 text-right text-xs text-zinc-500">{shadow.offsetY}</span>
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Blur</Label>
              <Slider
                min={0}
                max={30}
                step={1}
                value={[shadow.blur]}
                onValueChange={([v]: number[]) => updateShadow({ blur: v })}
                className="flex-1"
              />
              <span className="w-8 text-right text-xs text-zinc-500">{shadow.blur}</span>
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Cor</Label>
              <Input
                type="color"
                value={shadow.color.startsWith('rgba') ? '#000000' : shadow.color}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  updateShadow({ color: e.target.value })
                }
                className="h-7 w-12 cursor-pointer border-zinc-700 bg-zinc-800 p-0.5"
              />
            </div>
          </div>
        )}
      </div>

      <Separator className="bg-zinc-700" />

      {/* ─── Outline Section ─── */}
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <Label className="text-xs text-zinc-400">Contorno</Label>
          <Switch checked={outlineEnabled} onCheckedChange={handleOutlineToggle} />
        </div>
        {outlineEnabled && (
          <div className="flex flex-col gap-2 pl-2">
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Largura</Label>
              <Slider
                min={1}
                max={10}
                step={1}
                value={[outline.width]}
                onValueChange={([v]: number[]) => updateOutline({ width: v })}
                className="flex-1"
              />
              <span className="w-8 text-right text-xs text-zinc-500">{outline.width}px</span>
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Cor</Label>
              <Input
                type="color"
                value={outline.color}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  updateOutline({ color: e.target.value })
                }
                className="h-7 w-12 cursor-pointer border-zinc-700 bg-zinc-800 p-0.5"
              />
            </div>
          </div>
        )}
      </div>

      <Separator className="bg-zinc-700" />

      {/* ─── Gradient Section ─── */}
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <Label className="text-xs text-zinc-400">Gradiente</Label>
          <Switch checked={gradientEnabled} onCheckedChange={handleGradientToggle} />
        </div>
        {gradientEnabled && (
          <div className="flex flex-col gap-2 pl-2">
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Início</Label>
              <Input
                type="color"
                value={gradient.startColor}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  updateGradient({ startColor: e.target.value })
                }
                className="h-7 w-12 cursor-pointer border-zinc-700 bg-zinc-800 p-0.5"
              />
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Fim</Label>
              <Input
                type="color"
                value={gradient.endColor}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  updateGradient({ endColor: e.target.value })
                }
                className="h-7 w-12 cursor-pointer border-zinc-700 bg-zinc-800 p-0.5"
              />
            </div>
            <div className="flex items-center gap-2">
              <Label className="w-16 text-xs text-zinc-500">Direção</Label>
              <div className="flex gap-1">
                {GRADIENT_DIRECTIONS.map((dir) => (
                  <button
                    key={dir.value}
                    type="button"
                    onClick={() => updateGradient({ direction: dir.value })}
                    className={cn(
                      'rounded px-2 py-1 text-xs transition-colors',
                      gradient.direction === dir.value
                        ? 'bg-emerald-600 text-white'
                        : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700',
                    )}
                  >
                    {dir.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      <Separator className="bg-zinc-700" />

      {/* ─── Preview ─── */}
      <div className="flex flex-col gap-1">
        <Label className="text-xs text-zinc-400">Preview</Label>
        <div className="flex items-center justify-center rounded-md bg-zinc-800 p-4 border border-zinc-700 min-h-[60px]">
          <span style={previewStyle} className="text-white">
            {previewText}
          </span>
        </div>
      </div>
    </div>
  );
}

export default TextEffectsPanel;
